    [key: string]: any;
}

export interface ChatMessage {
    role: 'user' | 'model';
    content: string;
}

export interface VisibilityState {
    trendChart: boolean;
    industryGrid: boolean;
    employeeAnalysis: boolean;
    summaryTable: boolean;
}

export interface AnalysisRecord {
    timestamp: number;
    type: 'topSeller';
    analysis: string;
    dataUsed: Employee[];
}

export interface ColumnConfig {
    id: string;
    mainHeader: string;
    columnName: string;
    type: 'data' | 'calculated';

    // For 'data' type
    metricType?: 'quantity' | 'revenue' | 'revenueQD';
    filters?: {
        selectedIndustries: string[];
        selectedSubgroups: string[];
        selectedManufacturers: string[];
        productCodes: string[];
        priceType?: 'original' | 'discounted';
        priceCondition?: 'greater' | 'less' | 'equal' | 'between';
        priceValue1?: number;
        priceValue2?: number;
    };

    // For 'calculated' type
    operation?: '+' | '-' | '*' | '/';
    operand1_columnId?: string;
    operand2_columnId?: string;
    displayAs?: 'number' | 'percentage';

    conditionalFormatting?: {
        condition: '>' | '<' | '=' | 'between' | '>avg' | '<avg';
        value1: number;
        value2?: number;
        color: string;
    }[];
}

export interface ContestTableConfig {
    id: string;
    tableName: string;
    columns: ColumnConfig[];
    defaultSortColumnId?: string;
}

export interface CustomContestTab {
    id: string;
    name: string;
    icon: string;
    tables: ContestTableConfig[];
}

export interface HeadToHeadConditionalFormatRule {
  id: string;
  criteria: 'specific_value' | 'column_dept_avg' | 'row_avg';
  operator: '>' | '<' | '=';
  value: number;
  textColor: string;
  backgroundColor: string;
}

export interface HeadToHeadTableConfig {
    id: string;
    tableName: string;
    selectedSubgroups: string[];
    selectedParentGroups?: string[];
    metricType: 'revenue' | 'quantity' | 'revenueQD' | 'hieuQuaQD';
    totalCalculationMethod?: 'sum' | 'average';
    conditionalFormats?: HeadToHeadConditionalFormatRule[];
}

import React, { useEffect, useState } from 'react';
import DashboardView from './components/views/DashboardView';
import Sidebar from './components/layout/Sidebar';
import CouponConverterView from './components/views/CouponConverterView';
import EmployeeEfficiencyView from './components/views/employee-efficiency/EmployeeEfficiencyView';
import DailyChecklistReportView from './components/views/DailyChecklistReportView';
import ReportBiUpdateView from './components/views/ReportBiUpdateView';
import type { ViewType } from './types';

declare const lucide: any;

export default function App() {
    const [currentView, setCurrentView] = useState<ViewType>('dashboard');
    // Change default state to true (collapsed) for hover UI
    const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(true);
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

    useEffect(() => {
        if (typeof lucide !== 'undefined' && lucide) {
            lucide.createIcons();
        }
    }, [currentView, isSidebarCollapsed]);

    const renderView = () => {
        switch (currentView) {
            case 'dashboard':
                return <DashboardView />;
            case 'coupon':
                return <CouponConverterView />;
            case 'efficiency':
                return <EmployeeEfficiencyView />;
            case 'checklist':
                return <DailyChecklistReportView />;
            case 'bi_update':
                return <ReportBiUpdateView />;
            default:
                return <DashboardView />;
        }
    };

    return (
        <div className="flex min-h-screen bg-slate-50 dark:bg-slate-900 transition-colors duration-500 overflow-hidden">
            {/* Sidebar Navigation */}
            <Sidebar 
                currentView={currentView} 
                setCurrentView={setCurrentView}
                isCollapsed={isSidebarCollapsed}
                setIsCollapsed={setIsSidebarCollapsed}
                isMobileOpen={isMobileMenuOpen}
                setIsMobileOpen={setIsMobileMenuOpen}
            />

            {/* Main Application Area */}
            <main className={`flex-grow overflow-y-auto transition-all duration-300 ${isSidebarCollapsed ? 'md:ml-20' : 'md:ml-64'}`}>
                {/* Mobile Header (Hidden on Desktop) */}
