import * as XLSX from 'xlsx';

function normalizeStr(str: any) {
  if (!str) return '';
  return String(str).toLowerCase().trim();
}

self.onmessage = async (e) => {
  const { type, payload } = e.data;

  if (type === 'IMPORT_FILE') {
    try {
      const { file } = payload;
      const arrayBuffer = await file.arrayBuffer();
      const workbook = XLSX.read(new Uint8Array(arrayBuffer), { type: 'array', cellDates: true, dense: true });
      const sheet = workbook.Sheets[workbook.SheetNames[0]];
      const rawData: any[] = XLSX.utils.sheet_to_json(sheet, { defval: '' });

      // Lọc và chuẩn hóa dữ liệu ngay tại worker
      const processed = rawData.map(row => {
        const price = parseFloat(row['Giá bán_1']) || 0;
        // Logic hệ số quy đổi mặc định
        let factor = 1.0;
        const industry = String(row['Ngành hàng'] || '').toLowerCase();
        if (industry.includes('phụ kiện')) factor = 3.37;
        else if (industry.includes('gia dụng')) factor = 1.85;
        else if (industry.includes('bảo hiểm')) factor = 4.18;

        return {
          ...row,
          computedRevenue: price,
          computedRevenueQD: price * factor,
          normalizedKho: String(row['Mã kho tạo'] || ''),
          normalizedXuat: normalizeStr(row['Trạng thái xuất']).includes('da') ? 'Đã' : 'Chưa',
          normalizedNguoiTao: String(row['Người tạo'] || ''),
          parsedDate: row['Ngày tạo'] instanceof Date ? row['Ngày tạo'] : new Date(row['Ngày tạo'])
        };
      }).filter(r => r.parsedDate && !isNaN(r.parsedDate.getTime()));

      // Tính toán sơ bộ kết quả Dashboard
      const result = calculateMetrics(processed);
      self.postMessage({ type: 'SUCCESS', payload: result, raw: processed });
    } catch (err: any) {
      self.postMessage({ type: 'ERROR', message: err.message });
    }
  }
};

function calculateMetrics(rows: any[]) {
  const kpis = { doanhThuQD: 0, totalRevenue: 0, soLuongThuHo: 0, traGopPercent: 0, doanhThuQDChoXuat: 0 };
  const daily: any = {};
  const shifts: any = { "Ca 1": {revenue:0}, "Ca 2": {revenue:0}, "Ca 3": {revenue:0}, "Ca 4": {revenue:0}, "Ca 5": {revenue:0}, "Ca 6": {revenue:0} };

  rows.forEach(r => {
    kpis.totalRevenue += r.computedRevenue;
    kpis.doanhThuQD += r.computedRevenueQD;
    if (r.normalizedXuat === 'Chưa') kpis.doanhThuQDChoXuat += r.computedRevenueQD;

    // Logic Trends
    const dateKey = r.parsedDate.toISOString().split('T')[0];
    if (!daily[dateKey]) daily[dateKey] = { revenue: 0, revenueQD: 0, date: r.parsedDate };
    daily[dateKey].revenue += r.computedRevenue;
    daily[dateKey].revenueQD += r.computedRevenueQD;
  });

  return {
    kpis: { ...kpis, hieuQuaQD: kpis.totalRevenue > 0 ? (kpis.doanhThuQD / kpis.totalRevenue - 1) : 0 },
    trendData: { daily, shifts },
    lastUpdated: new Date().toLocaleTimeString()
  };
}

import { writable, get } from 'svelte/store';
import type { AppState, ProcessedData, FilterState } from '../types';

export const appState = writable<AppState>('upload');
export const isProcessing = writable(false);
export const processedData = writable<ProcessedData | null>(null);
export const originalData = writable<any[]>([]);

export const filterState = writable<FilterState>({
  kho: 'all',
  xuat: 'all',
  trangThai: [],
  nguoiTao: [],
  startDate: '',
  endDate: '',
  dateRange: 'all'
});

let worker: Worker;

export function initWorker() {
  worker = new Worker(new URL('../services/worker.ts', import.meta.url), { type: 'module' });
  worker.onmessage = (e) => {
    const { type, payload, raw } = e.data;
    if (type === 'SUCCESS') {
      processedData.set(payload);
      originalData.set(raw);
      appState.set('dashboard');
      isProcessing.set(false);
    }
  };
}

export function uploadFile(file: File) {
  isProcessing.set(true);
  appState.set('loading');
  worker.postMessage({ type: 'IMPORT_FILE', payload: { file } });
}

