let worker: Worker;
let timerInterval: any;

export function initWorker() {
  if (typeof Worker === 'undefined') return;

  worker = new Worker(new URL('../services/worker.ts', import.meta.url), { type: 'module' });

  worker.onmessage = (e) => {
    const { type, payload } = e.data;

    if (type === 'result') {
      const data = payload as any[];
      originalData.set(data);

      // Chạy xử lý dữ liệu để hiển thị lên Dashboard
      const result = processDashboardData(data);
      processedData.set(result);

      appState.set('dashboard');
      isProcessing.set(false);
      stopTimer();
    } else if (type === 'error') {
      showToast(payload, 'error');
      appState.set('upload');
      isProcessing.set(false);
      stopTimer();
    }
  };
}

function startTimer() {
  processingTime.set(0);
  const start = Date.now();
  timerInterval = setInterval(() => {
    processingTime.set(Date.now() - start);
  }, 100);
}

function stopTimer() {
  clearInterval(timerInterval);
}

export function triggerFileUpload(file: File) {
  if (!worker) initWorker();

  isProcessing.set(true);
  appState.set('loading');
  startTimer();

  worker.postMessage({ file, enableDeduplication: true });
}

export function showToast(message: string, type: 'success' | 'error' | 'info' = 'info') {
  toastMessage.set({ message, type });
  setTimeout(() => toastMessage.set(null), 3000);
}

/**
 * Load dữ liệu mẫu cho Demo
 */
export async function loadSampleData() {
  const { getSampleData } = await import('../services/sampleData');
  const data = getSampleData();

  isProcessing.set(true);
  appState.set('loading');
  startTimer();

  setTimeout(() => {
    originalData.set(data);
    const result = processDashboardData(data);
    processedData.set(result);
    appState.set('dashboard');
    isProcessing.set(false);
    stopTimer();
    fileInfo.set({ filename: 'Dữ liệu mẫu.xlsx', savedAt: new Date().toLocaleTimeString() });
  }, 1500);
}

