                                        </div>
                                    </div>

                                    <div data-debug-id="KpiCards" data-debug-info={JSON.stringify(debugInitialData.KpiCards)}>
                                        {isProcessing ? <KpiCardsSkeleton /> : <KpiCards onUnshippedClick={openUnshippedModal} />}
