                <DebugPanel 
                    isVisible={isDebugPanelVisible} 
                    isInspectorActive={isInspectorActive} 
                    info={debugInfo} 
                    onClose={() => setIsDebugPanelVisible(false)} 
                    onToggleInspector={() => setIsInspectorActive(p => !p)} 
                />
            </div>
        </div>
    );
}

